  .chat-page-shell .chat-action-button,
  .chat-page-shell .chat-actions > button {
    width: 2.25rem;
    height: 2.25rem;
    min-width: 2.25rem;
    min-height: 2.25rem;
    padding: 0;
    font-size: 0.875rem;
  }

  .chat-page-shell .chat-action-button svg,
  .chat-page-shell .chat-actions > button svg {
    width: 1rem;
    height: 1rem;
  }
}

@media (max-width: 640px) {
  .chat-page-shell .chat-action-button,
  .chat-page-shell .chat-actions > button {
    width: 2rem;
    height: 2rem;
    min-width: 2rem;
    min-height: 2rem;
    padding: 0;
  }
}

