// NOTE: no unconditional `inline-flex` here. An unconditional display utility
// (`inline-flex`) is not reliably overridden by an unconditional `hidden` in
// Tailwind v4, which would leave `chat-only-desktop` buttons visible at all
// widths. Each usage sets its own display (`inline-flex` when always shown, or
// `chat-only-desktop` when desktop-only — the responsive variant wins).
const actionButtonClass =
  "chat-action-button shrink-0 items-center justify-center rounded-md text-sm font-medium transition-colors hover:bg-accent hover:text-accent-foreground disabled:pointer-events-none disabled:opacity-50";

