/*
 * Responsive header visibility — driven from unlayered CSS (not Tailwind
 * `md:`/`lg:` variants), because Tailwind is compiled twice in this app
 * (app.css + pi-web-ui) and the duplicated base `.hidden`/`.inline-flex`
 * emitted last would otherwise clobber the responsive variants at all widths.
 * `.chat-only-desktop`: inline header actions, shown at md+ (>= 48rem).
 * `.chat-only-compact`: overflow-menu duplicates, shown below md (< 48rem).
 */
.chat-only-desktop {
  display: none;
}
@media (min-width: 48rem) {
  .chat-only-desktop {
    display: inline-flex;
  }
  .chat-only-compact {
    display: none;
  }
}

